import uuid
import pytest

def test_ach_transfer_above_limit_without_stepup_returns_422(api_client, verified_ach_customer):
    payload = {
        "amount": 15000.00,
        "currency": "USD",
        "ach_account_id": verified_ach_customer["ach_account_id"],
    }
    headers = {
        "Authorization": f"Bearer {verified_ach_customer['token']}",
        "Idempotency-Key": str(uuid.uuid4()),
    }
    resp = api_client.post("/transfers/ach", json=payload, headers=headers)
    assert resp.status_code == 422
    body = resp.json()
    assert body.get("error_code") == "STEP_UP_REQUIRED"

